function findExplanation(type, promptRaw, answerRaw) {
  const prompt = promptRaw.replace(/\\'/g, "'").toLowerCase();
  const answer = answerRaw.replace(/\\'/g, "'");

  // Try to find a matching key (longest match wins)
  let bestMatch = null;
  let bestLen = 0;
  for (const key of Object.keys(EXPLANATIONS)) {
    if (prompt.includes(key) && key.length > bestLen) {
      bestMatch = key;
      bestLen = key.length;
    }
  }

  if (bestMatch) {
    return EXPLANATIONS[bestMatch];
  }

  // Fallback: generate a generic but still useful explanation
  if (type === 'true_false') {
    if (answer === 'True') {
      const stmt = promptRaw.replace(/\\'/g, "'").replace(/\.$/, '');
      return `This is correct. ${stmt}.`;
    } else {
      return `This is actually false. The correct understanding is the opposite of what this statement claims.`;
    }
  }
  if (type === 'swipe_judge') {
    const action = promptRaw.replace(/\\'/g, "'").replace(/\.$/, '');
    if (answer === 'Good practice' || answer === 'Good technique' || answer === 'Good misdirection') {
      return `${action} is a recommended approach that supports effective skill development.`;
    } else {
      return `${action} should be avoided as it can hinder progress or lead to negative outcomes.`;
    }
  }
  if (type === 'fill_gap') {
    const filled = promptRaw.replace(/\\'/g, "'").replace('___', answer);
    return `${filled}`;
  }
  if (type === 'before_after') {
    return `The better option demonstrates the recommended approach that produces superior results in practice.`;
  }
  // multiple_choice fallback
  return `The correct answer is "${answer.length > 80 ? answer.substring(0, 77) + '...' : answer}" as it most accurately addresses the concept being tested.`;
}

function processFile(filePath) {
  let content = fs.readFileSync(filePath, 'utf8');
  const lines = content.split('\n');
  let modified = 0;
  let unmatched = [];

  const newLines = lines.map((line) => {
    if (line.includes('explanation:')) return line;
    if (!line.includes("type: '") || !line.includes("correctAnswer:") || !line.includes("difficulty:")) return line;

    const typeMatch = line.match(/type: '([^']+)'/);
    const promptMatch = line.match(/prompt: '((?:[^'\\]|\\.)*)'/);
    const correctAnswerMatch = line.match(/correctAnswer: '((?:[^'\\]|\\.)*)'/);

    if (!typeMatch || !promptMatch || !correctAnswerMatch) return line;

    const qType = typeMatch[1];
    const qPrompt = promptMatch[1];
    const qAnswer = correctAnswerMatch[1];

    let explanation = findExplanation(qType, qPrompt, qAnswer);
    // Escape single quotes
    explanation = explanation.replace(/'/g, "\\'");

    // Insert before closing }
    const closingBrace = line.lastIndexOf('}');
    if (closingBrace === -1) return line;

    const beforeBrace = line.substring(0, closingBrace).trimEnd();
    const newLine = beforeBrace + `, explanation: '${explanation}' ` + line.substring(closingBrace);

    // Track if we used fallback
    const promptLower = qPrompt.replace(/\\'/g, "'").toLowerCase();
    let found = false;
    for (const key of Object.keys(EXPLANATIONS)) {
      if (promptLower.includes(key)) { found = true; break; }
    }
    if (!found) {
      unmatched.push(qPrompt.substring(0, 60));
    }

    modified++;
    return newLine;
  });

  if (modified > 0) {
    fs.writeFileSync(filePath, newLines.join('\n'), 'utf8');
  }
  console.log(`${path.basename(filePath)}: added ${modified} explanations` + (unmatched.length > 0 ? ` (${unmatched.length} fallback)` : ''));
  if (unmatched.length > 0) {
    unmatched.forEach(u => console.log(`  FALLBACK: ${u}`));
  }

  return modified;
}

let totalModified = 0;
for (const file of FILES) {
  const filePath = path.join(QUESTIONS_DIR, file);
  if (fs.existsSync(filePath)) {
    totalModified += processFile(filePath);
  } else {
    console.log(`File not found: ${file}`);
  }
}
console.log(`\nTotal explanations added: ${totalModified}`);
